/**
 * Heavyweight dogfooding — run the REAL polyglot scanner + Betty + bridge
 * on a project. This is the full pipeline: tree-sitter ASTs → GG topology
 * → Betty beta1/deficit → CheckpointedSystem → diagnosis.
 *
 * Usage: npx tsx src/dogfood-heavyweight.ts [project-path]
 * Default: scans gnosis/src/checkpoint-substrates.ts as a smoke test,
 *          then scans a sample of gnosis source files.
 */

import { resolve, relative, extname, join } from 'path';
import { readdirSync, readFileSync } from 'fs';
import { analyzePolyglotSource } from './polyglot-bridge';
import {
  diagnoseProject,
  type FunctionMetrics,
} from './polyglot-checkpoint-bridge';

const GNOSIS_ROOT = resolve(import.meta.dirname, '..');

// ── File discovery (same ignored dirs as organism-topology) ────────

const IGNORED_DIRS = new Set([
  'node_modules', '.next', 'dist', 'build', '.git', 'coverage',
  '.wrangler', '__tests__', '.a0', '.gnosis', '.lake', '.tmp',
  'target', '.turbo', 'storybook-static',
]);

const SCANNABLE = new Set(['.ts', '.tsx', '.js', '.jsx']);

function walkSourceFiles(root: string): string[] {
  const files: string[] = [];
  const queue = [root];
  while (queue.length > 0) {
    const dir = queue.pop()!;
    let entries;
    try { entries = readdirSync(dir, { withFileTypes: true }); } catch { continue; }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        if (!IGNORED_DIRS.has(entry.name)) queue.push(join(dir, entry.name));
      } else if (SCANNABLE.has(extname(entry.name))) {
        files.push(join(dir, entry.name));
      }
    }
  }
  return files;
}

// ── Main ───────────────────────────────────────────────────────────

const projectPath = process.argv[2]
  ? resolve(process.argv[2])
  : GNOSIS_ROOT;

const projectName = relative(resolve(projectPath, '..', '..'), projectPath) || 'gnosis';

console.log(`\nHeavyweight scan: ${projectName}`);
console.log(`Path: ${projectPath}`);
console.log('='.repeat(70));

const allFiles = walkSourceFiles(resolve(projectPath, 'src'));

// Take a sample — full scan of 600+ files takes minutes
const sampleSize = parseInt(process.argv[3] ?? '30', 10);
const sample = allFiles.slice(0, sampleSize);

console.log(`\nScanning ${sample.length} of ${allFiles.length} source files...\n`);

const fileResults: Array<{ filePath: string; result: Awaited<ReturnType<typeof analyzePolyglotSource>> }> = [];
const errors: string[] = [];
let scanned = 0;

for (const filePath of sample) {
  try {
    const result = await analyzePolyglotSource(filePath);
    fileResults.push({ filePath, result });
    scanned++;
    const funcs = result.functions.length;
    const errs = result.errors.length;
    const rel = relative(projectPath, filePath);
    if (funcs > 0 || errs > 0) {
      console.log(`  [${String(scanned).padStart(3)}] ${rel.padEnd(50)} ${funcs} funcs  ${errs} errs`);
    }
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : String(e);
    errors.push(`${relative(projectPath, filePath)}: ${msg}`);
  }
}

console.log(`\nScanned: ${scanned} files, ${errors.length} errors`);

// ── Run through the bridge ─────────────────────────────────────────

const profile = diagnoseProject(projectName, fileResults);

console.log('\n' + '='.repeat(70));
console.log('CHECKPOINT DIAGNOSIS (from real scanner)');
console.log('='.repeat(70));
console.log(`Functions analyzed:  ${profile.scan.functionCount}`);
console.log(`Active channels:    ${profile.activeChannels} (beta1 > 0)`);
console.log(`Destroyed channels: ${profile.destroyedChannels} (beta1 = 0)`);
console.log(`Sigma:              ${profile.sigma.toFixed(4)}`);
console.log(`Health:             ${profile.diagnosis.health}`);
console.log(`Repair path:        ${profile.diagnosis.repairPath}`);
console.log(`Total beta1:        ${profile.scan.totalBeta1}`);
console.log(`Total deficit:      ${profile.scan.totalDeficit}`);
console.log(`Total god weight:   ${profile.scan.totalGodWeight}`);
console.log(`Max god weight:     ${profile.scan.maxGodWeight}`);
console.log(`Hotspots:           ${profile.scan.hotspotCount}`);

// Purity-calibrated diagnosis
const pp = profile.purityProfile;
console.log(`\nPURITY CALIBRATION:`);
console.log(`  Pure functions:     ${pp.pureFunctions} (${(pp.purityRatio * 100).toFixed(1)}%)`);
console.log(`  Branching funcs:    ${pp.branchingFunctions} (${(pp.branchingFunctions / Math.max(1, pp.totalFunctions) * 100).toFixed(1)}%)`);
console.log(`  Looping funcs:      ${pp.loopingFunctions} (${(pp.loopingFunctions / Math.max(1, pp.totalFunctions) * 100).toFixed(1)}%)`);
console.log(`  Purity baseline:    ${pp.purityBaseline.toFixed(3)} (expected deafness from pure functions)`);
console.log(`  Raw sigma:          ${profile.sigma.toFixed(4)}`);
console.log(`  Adjusted sigma:     ${pp.adjustedSigma.toFixed(4)} (raw - baseline)`);
console.log(`  Raw health:         ${profile.diagnosis.health}`);
console.log(`  ADJUSTED HEALTH:    ${pp.adjustedHealth}`);
console.log(`Ghost mass:         ${profile.scan.totalGhostMass.toFixed(2)}`);
console.log(`Void dimensions:    ${profile.scan.totalVoidDimensions}`);
console.log(`Buley measure:      ${profile.scan.totalBuleyMeasure.toFixed(2)}`);

// ── Void dimension profile ─────────────────────────────────────────

console.log('\nVOID DIMENSIONS:');
for (const a of profile.voidProfile.assessments) {
  console.log(`  ${a.dimension.padEnd(12)} visible=${a.visibleCrossings}  invisible=${a.invisibleCrossings}  total=${a.totalCrossings}  ${a.gapIsLowerBound ? '(lower bound)' : '(exact)'}`);
}
console.log(`  composite    rank1=${profile.voidProfile.composite.rank1}  rank0=${profile.voidProfile.composite.rank0}`);

// ── Repair ordering ────────────────────────────────────────────────

if (profile.repairOrdering.length > 0) {
  console.log('\nREPAIR ORDERING (top 10 by God Formula weight):');
  for (const candidate of profile.repairOrdering) {
    const rel = relative(projectPath, candidate.filePath);
    console.log(`  ${candidate.functionName.padEnd(35)} godWeight=${String(candidate.godWeight).padStart(3)}  beta1=${candidate.beta1}  deficit=${candidate.deficit}  ghost=${candidate.ghostMass.toFixed(1)}  ${rel}`);
  }
}

// ── Forecasts ──────────────────────────────────────────────────────

console.log('\nFORECASTS:');
console.log(`  If repaired (+1): sigma=${profile.forecastIfRepaired.sicknessFraction.toFixed(4)}  health would be ${profile.forecastIfRepaired.isDeaf ? 'necrotic' : profile.forecastIfRepaired.sicknessFraction < 0.1 ? 'healthy' : 'stressed'}`);
console.log(`  If neglected (-1): sigma=${profile.forecastIfNeglected.sicknessFraction.toFixed(4)}  ${profile.forecastIfNeglected.isDeaf ? 'NECROTIC — all channels destroyed' : ''}`);

// ── Per-function detail ────────────────────────────────────────────

const allFuncs = profile.scan.functions;
const active = allFuncs.filter(f => f.healthClass === 'active');
const covered = allFuncs.filter(f => f.healthClass === 'covered');
const deaf = allFuncs.filter(f => f.healthClass === 'deaf');
const silent = allFuncs.filter(f => f.healthClass === 'silent');
const healthy = active.length + covered.length + silent.length;
const sick = deaf.length;

console.log(`\nFUNCTION HEALTH (4-way classification):`);
console.log(`  active  (internal feedback):   ${String(active.length).padStart(4)}  ${(active.length / allFuncs.length * 100).toFixed(1)}%  HEALTHY`);
console.log(`  covered (test coverage):       ${String(covered.length).padStart(4)}  ${(covered.length / allFuncs.length * 100).toFixed(1)}%  HEALTHY`);
console.log(`  silent  (pure, no branching):  ${String(silent.length).padStart(4)}  ${(silent.length / allFuncs.length * 100).toFixed(1)}%  HEALTHY`);
console.log(`  deaf    (branching, no feedback): ${String(deaf.length).padStart(4)}  ${(deaf.length / allFuncs.length * 100).toFixed(1)}%  SICK`);
console.log(`  ──────────────────────────────────`);
console.log(`  healthy: ${healthy} (${(healthy / allFuncs.length * 100).toFixed(1)}%)  |  sick: ${sick} (${(sick / allFuncs.length * 100).toFixed(1)}%)`);

if (deaf.length > 0) {
  console.log('\n  ACTUALLY SICK — deaf functions (branching, no feedback, no tests):');
  const topDeaf = deaf.sort((a, b) => b.buleyMeasure - a.buleyMeasure).slice(0, 10);
  for (const f of topDeaf) {
    const rel = relative(projectPath, f.filePath);
    console.log(`    ${f.functionName.padEnd(35)} buley=${f.buleyMeasure.toFixed(1)}  voidDims=${f.voidDimensions}  ${rel}`);
  }
  console.log(`\n  Treatment: add try/catch (--fix) or write tests for these ${deaf.length} functions.`);
}

if (errors.length > 0) {
  console.log(`\nSCAN ERRORS (${errors.length}):`);
  for (const e of errors.slice(0, 10)) {
    console.log(`  ${e}`);
  }
}
